// Pre-computed set of all layout placeholder text (used by applyLayout to detect user vs placeholder text)
const _ALL_LAYOUT_DEFAULTS = new Set();
LAYOUTS.forEach(lay => {
  lay.elements.forEach(el => {
    if (el.t === 'text' && el.txt) {
      _ALL_LAYOUT_DEFAULTS.add(el.txt.toLowerCase().trim());
    }
  });
});

